/**
 * Array of panel names rendered in the page component.
 * @public
 */
export declare const pagePanels: readonly ["sidebar", "main", "details"];
/** @public */
export type PanelName = (typeof pagePanels)[number];
/**
 * An object of panel keys and the panel's current size in all available units.
 * @public
 */
export type PagePanelSizes = Record<string, {
    [key in 'px' | '%']: number;
}>;
/**
 * Page panels that can be dismissed.
 * @public
 * @deprecated This type is no longer used and will be removed in a future release.
 */
export type DismissiblePagePanels = Extract<(typeof pagePanels)[number], 'sidebar' | 'details'>;
/** @public */
export type ControlledPagePanelProps = {
    /** If the panel is opened. */
    dismissed: boolean;
    /** If the panel is dismissed by default. */
    defaultDismissed?: never;
};
/** @public */
export type UncontrolledPagePanelProps = {
    /** If the panel is opened. */
    dismissed?: never;
    /** If the panel is dismissed by default. */
    defaultDismissed?: boolean;
};
/**
 * @public
 * @deprecated Use `ControlledPagePanelProps` or `UncontrolledPagePanelProps` instead.
 **/
export type PagePanelProps = ControlledPagePanelProps | UncontrolledPagePanelProps;
